// Filter orders from last 24 hours
const cutoff = new Date(Date.now() - 24 * 60 * 60 * 1000);

return items.filter(i => new Date(i.json.date_created) >= cutoff);

let revenue = 0;
let count = items.length;
let currency = null;

for (const i of items) {
  revenue += parseFloat(i.json.total || 0);
  if (!currency) currency = i.json.currency;
}

const aov = count > 0 ? revenue / count : 0;

return [{ json: { totalRevenue: revenue.toFixed(2), orderCount: count, aov: aov.toFixed(2), currency } }];

const productMap = {};

for (const item of items) {
  for (const line of item.json.line_items || []) {
    productMap[line.name] = (productMap[line.name] || 0) + line.quantity;
  }
}

const topProducts = Object.entries(productMap)
  .sort((a,b) => b[1] - a[1])
  .slice(0,5);

return [{ json: { topProducts } }];

let result = {};

for (const i of items) {
  result = { ...result, ...i.json };
}

return [{ json: result }];

